"use client";

import { useTranslations } from "next-intl";
import { Link } from "@/lib/navigation";
import { useRouter } from "next/navigation";
import { useState, useTransition } from "react";
import { deletePost } from "@/app/[locale]/(admin)/admin/posts/actions";

type PostRow = {
  id: string;
  slug: string;
  status: string;
  primary_locale: string;
  updated_at: string;
  profiles: { display_name: string | null } | { display_name: string | null }[] | null;
};

function getDisplayName(profiles: PostRow["profiles"]): string | null {
  if (!profiles) return null;
  if (Array.isArray(profiles)) return profiles[0]?.display_name ?? null;
  return profiles.display_name ?? null;
}

const STATUS_COLORS: Record<string, string> = {
  idea: "bg-gray-100 text-gray-700 dark:bg-gray-700 dark:text-gray-300",
  research: "bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300",
  draft: "bg-yellow-100 text-yellow-700 dark:bg-yellow-900/40 dark:text-yellow-300",
  optimize: "bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300",
  format: "bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300",
  review: "bg-pink-100 text-pink-700 dark:bg-pink-900/40 dark:text-pink-300",
  approved: "bg-teal-100 text-teal-700 dark:bg-teal-900/40 dark:text-teal-300",
  scheduled: "bg-indigo-100 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300",
  published: "bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-300",
  archived: "bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-300",
};

export function DashboardPostsTable({
  posts,
  isAdmin,
}: {
  posts: PostRow[];
  isAdmin: boolean;
}) {
  const t = useTranslations();
  const router = useRouter();
  const [isPending, startTransition] = useTransition();
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  async function handleDelete(postId: string, slug: string) {
    if (!confirm(t("dashboard.confirmDelete", { slug }))) return;
    setDeletingId(postId);
    setError(null);
    const result = await deletePost(postId);
    if (result.error) {
      setError(result.error);
      setDeletingId(null);
      return;
    }
    startTransition(() => {
      router.refresh();
    });
    setDeletingId(null);
  }

  return (
    <section className="mt-8">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
          {isAdmin ? t("dashboard.allPosts") : t("dashboard.myPosts")}
        </h2>
        <Link
          href="/admin/posts/new"
          className="px-4 py-2 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-sm font-medium rounded hover:bg-gray-700 dark:hover:bg-gray-300 transition-colors"
        >
          + {t("dashboard.newPost")}
        </Link>
      </div>

      {error && (
        <p className="mb-4 text-sm text-red-600 dark:text-red-400">{error}</p>
      )}

      {posts.length === 0 ? (
        <div className="py-12 text-center text-gray-500 dark:text-gray-400 border border-dashed border-gray-300 dark:border-gray-600 rounded-lg">
          {t("dashboard.noPostsYet")}
        </div>
      ) : (
        <div className="overflow-x-auto rounded-lg border border-gray-200 dark:border-gray-700">
          <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700 text-sm">
            <thead className="bg-gray-50 dark:bg-gray-800">
              <tr>
                {isAdmin && (
                  <th className="px-4 py-3 text-left font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider text-xs">
                    {t("dashboard.author")}
                  </th>
                )}
                <th className="px-4 py-3 text-left font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider text-xs">
                  Slug
                </th>
                <th className="px-4 py-3 text-left font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider text-xs">
                  {t("admin.status")}
                </th>
                <th className="px-4 py-3 text-left font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider text-xs">
                  {t("admin.primaryLocale")}
                </th>
                <th className="px-4 py-3 text-left font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider text-xs">
                  Updated
                </th>
                <th className="px-4 py-3" />
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-gray-900 divide-y divide-gray-100 dark:divide-gray-800">
              {posts.map((post) => {
                const authorName = getDisplayName(post.profiles);
                const statusColor =
                  STATUS_COLORS[post.status] ?? STATUS_COLORS.idea;
                const isDeleting = deletingId === post.id;
                return (
                  <tr key={post.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
                    {isAdmin && (
                      <td className="px-4 py-3 text-gray-700 dark:text-gray-300 font-medium">
                        {authorName ?? (
                          <span className="text-gray-400 italic">Unknown</span>
                        )}
                      </td>
                    )}
                    <td className="px-4 py-3 font-mono text-gray-900 dark:text-gray-100">
                      {post.slug}
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${statusColor}`}
                      >
                        {post.status}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-gray-600 dark:text-gray-400 uppercase text-xs">
                      {post.primary_locale}
                    </td>
                    <td className="px-4 py-3 text-gray-500 dark:text-gray-400 whitespace-nowrap">
                      {new Date(post.updated_at).toLocaleDateString()}
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-3 justify-end">
                        <Link
                          href={`/admin/posts/${post.id}`}
                          className="text-blue-600 dark:text-blue-400 hover:underline font-medium"
                        >
                          {t("common.edit")}
                        </Link>
                        <button
                          onClick={() => handleDelete(post.id, post.slug)}
                          disabled={isDeleting || isPending}
                          className="text-red-600 dark:text-red-400 hover:underline font-medium disabled:opacity-50"
                        >
                          {isDeleting ? "…" : t("common.delete")}
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </section>
  );
}
